{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires reconstructing a sequence of operations based on tree structures. This involves identifying the parent-child relationships, determining the order of sibling merges, and ensuring the sequence is valid according to the rules of tree merging.",
  "helpers": [
    {
      "label": "tree_structure_analyzer",
      "instructions": "Given the initial tree and the final tree, identify the set of nodes that were merged. Specifically, for each node in the final tree, determine which nodes from the initial tree constitute its children and identify which sibling-merge operations must have occurred to reduce the initial child count to the final child count."
    },
    {
      "label": "operation_sequencer",
      "instructions": "Based on the identified merges, construct a valid chronological sequence of operations. A merge operation takes two adjacent siblings and replaces them with a single node. Ensure that the sequence respects the tree hierarchy, meaning a node can only be merged with its siblings after its own subtrees have been processed if necessary, or according to the specific rules of the problem."
    },
    {
      "label": "validity_verifier",
      "instructions": "Take a proposed sequence of merge operations and the initial tree, and simulate the process step-by-step to see if it results in the target final tree. Check for any illegal operations, such as merging non-adjacent siblings or attempting to merge nodes that no longer exist in the current state of the tree."
    }
  ],
  "synthesis_brief": "Combine the structural analysis of which nodes were merged with the generated sequence of operations. Use the verifier to confirm the sequence is correct. The final answer should be the sequence of operations that transforms the initial tree into the final tree."
}

